/// Convert the contract's Edit to the wire's, verb by verb.
fn edit_to_proto(value: theseus_modeling::Edit) -> proto::Edit {
    match value {
        theseus_modeling::Edit::Add { parent, kind, name, attrs } => {
            proto::Edit {
                verb: Some(
                    proto::edit::Verb::Add(proto::edit::Add {
                        parent,
                        kind,
                        name,
                        attrs: attrs.into_iter().collect(),
                    }),
                ),
            }
        }
        theseus_modeling::Edit::Remove { target } => {
            proto::Edit {
                verb: Some(proto::edit::Verb::Remove(proto::edit::Remove { target })),
            }
        }
        theseus_modeling::Edit::Rename { target, to } => {
            proto::Edit {
                verb: Some(proto::edit::Verb::Rename(proto::edit::Rename { target, to })),
            }
        }
        theseus_modeling::Edit::Set { target, attrs } => {
            proto::Edit {
                verb: Some(
                    proto::edit::Verb::Set(proto::edit::Set {
                        target,
                        attrs: attrs.into_iter().collect(),
                    }),
                ),
            }
        }
    }
}

/// Map a status back onto the contract: UNIMPLEMENTED is the typed
/// unimplemented default, PERMISSION_DENIED the typed refusal, anything
/// else the status itself.
fn failed(operation: &'static str, status: tonic::Status) -> anyhow::Error {
    match status.code() {
        tonic::Code::Unimplemented => theseus::Unimplemented(operation).into(),
        tonic::Code::PermissionDenied => theseus::Refused.into(),
        _ => anyhow::anyhow!("`{operation}` failed: {status}"),
    }
}

fn parsed<T: serde::de::DeserializeOwned>(
    operation: &'static str,
    body: &str,
) -> anyhow::Result<T> {
    serde_json::from_str(body)
        .map_err(|error| anyhow::anyhow!("`{operation}` reply did not parse: {error}"))
}
